/**
 * @brief Initialize the CAN peripheral with specified configuration
 * @param config Pointer to CAN configuration structure
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CAN_Init(const CAN_Config *config)
{
    log_debug("CAN: Initializing CAN");

    HAL_StatusTypeDef status = HAL_ERROR;

    if (config == NULL) {
        return HAL_ERROR;
    }

    /* Reset status */
    memset(&can_status, 0, sizeof(CAN_Status));

    /* Configure CAN peripheral */
    hcan.Instance = CAN1;
    hcan.Init.Mode = config->mode;

    hcan.Init.AutoRetransmission = config->auto_retransmission ? ENABLE : DISABLE;
    hcan.Init.AutoBusOff = config->auto_bus_off_recovery ? ENABLE : DISABLE;
    hcan.Init.TimeTriggeredMode = config->time_triggered_comm ? ENABLE : DISABLE;

    /* Configure baud rate */
    status = CAN_ConfigureBaudRate(config);
    if (status != HAL_OK) {
        return status;
    }

    /* Initialize CAN peripheral */
    status = HAL_CAN_Init(&hcan);
    if (status != HAL_OK) {
        return status;
    }

    /* Start CAN peripheral */
    status = HAL_CAN_Start(&hcan);
    if (status != HAL_OK) {
        return status;
    }

    /* Mark as initialized */
    can_status.initialized = true;

    log_debug("CAN: CAN initialized successfully");

    return HAL_OK;
}

/**
 * @brief Deinitialize the CAN peripheral
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CAN_DeInit(void)
{
    HAL_StatusTypeDef status = HAL_OK;

    /* Stop CAN peripheral */
    status = HAL_CAN_Stop(&hcan);
    if (status != HAL_OK) {
        return status;
    }

    /* Deinitialize CAN peripheral */
    status = HAL_CAN_DeInit(&hcan);
    if (status != HAL_OK) {
        return status;
    }

    /* Reset status */
    memset(&can_status, 0, sizeof(CAN_Status));

    /* Reset callbacks */
    tx_callback = NULL;
    rx_callback = NULL;
    error_callback = NULL;

    return HAL_OK;
}

/**
 * @brief Configure CAN filter
 * @param filter_config Pointer to filter configuration structure
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CAN_ConfigFilter(const CAN_FilterConfig *filter_config)
{
    CAN_FilterTypeDef filter;

    if (filter_config == NULL || filter_config->filter_bank >= CAN_MAX_FILTER_BANKS) {
        return HAL_ERROR;
    }

    /* Configure filter */
    filter.FilterBank = filter_config->filter_bank;
    filter.FilterMode = (filter_config->mode == CAN_FILTER_MODE_ID_MASK) ?
                       CAN_FILTERMODE_IDMASK : CAN_FILTERMODE_IDLIST;
    filter.FilterScale = (filter_config->scale == CAN_FILTER_SCALE_16BIT) ?
                        CAN_FILTERSCALE_16BIT : CAN_FILTERSCALE_32BIT;
    filter.FilterIdHigh = (uint16_t)(filter_config->id >> CAN_ID_HIGH_SHIFT);
    filter.FilterIdLow = (uint16_t)filter_config->id;
    filter.FilterMaskIdHigh = (uint16_t)(filter_config->mask >> CAN_ID_HIGH_SHIFT);
    filter.FilterMaskIdLow = (uint16_t)filter_config->mask;
    filter.FilterFIFOAssignment = CAN_RX_FIFO0;
    filter.FilterActivation = filter_config->enable ? ENABLE : DISABLE;

    return HAL_CAN_ConfigFilter(&hcan, &filter);
}

/**
 * @brief Transmit a CAN frame
 * @param frame Pointer to CAN frame structure
 * @param timeout Timeout value in milliseconds
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CAN_Transmit(const CAN_Frame *frame, uint32_t timeout)
{
    CAN_TxHeaderTypeDef tx_header;
    uint32_t tx_mailbox = 0;
    HAL_StatusTypeDef status = HAL_OK;

    if (frame == NULL || frame->data_length > CAN_MAX_DATA_LENGTH) {
        return HAL_ERROR;
    }

    /* Configure transmit header */
    tx_header.StdId = (frame->frame_type == CAN_FRAME_STANDARD) ? frame->id : 0;
    tx_header.ExtId = (frame->frame_type == CAN_FRAME_EXTENDED) ? frame->id : 0;
    tx_header.IDE = (frame->frame_type == CAN_FRAME_STANDARD) ?
                   CAN_ID_STD : CAN_ID_EXT;
    tx_header.RTR = frame->remote_request ? CAN_RTR_REMOTE : CAN_RTR_DATA;
    tx_header.DLC = frame->data_length;
    tx_header.TransmitGlobalTime = DISABLE;

    /* Transmit message */
    status = HAL_CAN_AddTxMessage(&hcan, &tx_header, frame->data, &tx_mailbox);
    if (status != HAL_OK) {
        return status;
    }

    /* Wait for transmission complete if timeout specified */
    if (timeout > 0) {
        uint32_t start_time = HAL_GetTick();
        while (HAL_CAN_IsTxMessagePending(&hcan, tx_mailbox)) {
            if ((HAL_GetTick() - start_time) > timeout) {
                return HAL_TIMEOUT;
            }
        }
    }

    /* Update statistics */
    can_status.tx_count++;

    return HAL_OK;
}

/**
 * @brief Receive a CAN frame
 * @param frame Pointer to CAN frame structure to store received data
 * @param timeout Timeout value in milliseconds
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CAN_Receive(CAN_Frame *frame, uint32_t timeout)
{
    CAN_RxHeaderTypeDef rx_header;
    HAL_StatusTypeDef status = HAL_OK;

    if (frame == NULL) {
        return HAL_ERROR;
    }

    /* Check if message is pending */
    if (!CAN_IsReceivePending(0) && !CAN_IsReceivePending(1)) {
        if (timeout == 0) {
            return HAL_ERROR; /* No message available */
        }

        /* Wait for message with timeout */
        uint32_t start_time = HAL_GetTick();
        while (!CAN_IsReceivePending(0) && !CAN_IsReceivePending(1)) {
            if ((HAL_GetTick() - start_time) > timeout) {
                return HAL_TIMEOUT;
            }
        }
    }

    /* Receive message from FIFO 0 first, then FIFO 1 */
    uint32_t fifo = CAN_IsReceivePending(0) ? CAN_RX_FIFO0 : CAN_RX_FIFO1;

    status = HAL_CAN_GetRxMessage(&hcan, fifo, &rx_header, frame->data);
    if (status != HAL_OK) {
        return status;
    }

    /* Fill frame structure */
    frame->id = (rx_header.IDE == CAN_ID_STD) ? rx_header.StdId : rx_header.ExtId;
    frame->frame_type = (rx_header.IDE == CAN_ID_STD) ?
                       CAN_FRAME_STANDARD : CAN_FRAME_EXTENDED;
    frame->data_length = rx_header.DLC;
    frame->remote_request = (rx_header.RTR == CAN_RTR_REMOTE);
    frame->timestamp = rx_header.Timestamp;

    /* Update statistics */
    can_status.rx_count++;

    /* Call receive callback if registered */
    if (rx_callback != NULL) {
        rx_callback(frame);
    }

    return HAL_OK;
}

/**
 * @brief Check if transmit mailbox is available
 * @return bool True if mailbox available, false otherwise
 */
bool CAN_IsTransmitMailboxAvailable(void)
{
    return (HAL_CAN_GetTxMailboxesFreeLevel(&hcan) > 0);
}

/**
 * @brief Check if receive FIFO has pending messages
 * @param fifo_number FIFO number (0 or 1)
 * @return bool True if messages pending, false otherwise
 */
bool CAN_IsReceivePending(uint8_t fifo_number)
{
    if (fifo_number > 1) {
        return false;
    }

    uint32_t fifo = (fifo_number == 0) ? CAN_RX_FIFO0 : CAN_RX_FIFO1;
    return (HAL_CAN_GetRxFifoFillLevel(&hcan, fifo) > 0);
}

/**
 * @brief Get number of pending messages in receive FIFO
 * @param fifo_number FIFO number (0 or 1)
 * @return uint8_t Number of pending messages
 */
uint8_t CAN_GetReceivePendingCount(uint8_t fifo_number)
{
    if (fifo_number > 1) {
        return 0;
    }

    uint32_t fifo = (fifo_number == 0) ? CAN_RX_FIFO0 : CAN_RX_FIFO1;
    return HAL_CAN_GetRxFifoFillLevel(&hcan, fifo);
}

/**
 * @brief Abort transmission for specified mailbox
 * @param mailbox_number Mailbox number (0-2)
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CAN_AbortTransmit(uint8_t mailbox_number)
{
    if (mailbox_number >= CAN_MAX_MAILBOXES) {
        return HAL_ERROR;
    }

    uint32_t mailbox = (mailbox_number == 0) ? CAN_TX_MAILBOX0 :
                      (mailbox_number == 1) ? CAN_TX_MAILBOX1 : CAN_TX_MAILBOX2;

    return HAL_CAN_AbortTxRequest(&hcan, mailbox);
}

