/* Private Functions */

/**
 * @brief Configure CAN baud rate based on configuration
 * @param config Pointer to CAN configuration structure
 * @return HAL_StatusTypeDef HAL status
 */
static HAL_StatusTypeDef CAN_ConfigureBaudRate(const CAN_Config *config)
{
    /* Default timing for 500kbps at 45MHz APB1 clock */
    if (config->baud_rate == CAN_BAUD_500KBPS) {
        hcan.Init.Prescaler = 9;
        hcan.Init.SyncJumpWidth = CAN_SJW_1TQ;
        hcan.Init.TimeSeg1 = CAN_BS1_13TQ;
        hcan.Init.TimeSeg2 = CAN_BS2_2TQ;
    }
    /* Default timing for 250kbps at 45MHz APB1 clock */
    else if (config->baud_rate == CAN_BAUD_250KBPS) {
        hcan.Init.Prescaler = CAN_PRESCALER_250KBPS;
        hcan.Init.SyncJumpWidth = CAN_SJW_1TQ;
        hcan.Init.TimeSeg1 = CAN_BS1_13TQ;
        hcan.Init.TimeSeg2 = CAN_BS2_2TQ;
    }
    /* Default timing for 125kbps at 45MHz APB1 clock */
    else if (config->baud_rate == CAN_BAUD_125KBPS) {
        hcan.Init.Prescaler = CAN_PRESCALER_125KBPS;
        hcan.Init.SyncJumpWidth = CAN_SJW_1TQ;
        hcan.Init.TimeSeg1 = CAN_BS1_13TQ;
        hcan.Init.TimeSeg2 = CAN_BS2_2TQ;
    }
    /* Custom timing */
    else {
        hcan.Init.Prescaler = config->prescaler;
        hcan.Init.SyncJumpWidth = config->sync_jump_width;
        hcan.Init.TimeSeg1 = config->time_segment_1;
        hcan.Init.TimeSeg2 = config->time_segment_2;
    }

    return HAL_OK;
}

/**
 * @brief Get current CAN error type
 * @return CAN_ErrorType Current error type
 */
static CAN_ErrorType CAN_GetErrorType(void)
{
    uint32_t error = HAL_CAN_GetError(&hcan);

    if (error & HAL_CAN_ERROR_STF) {
        return CAN_ERROR_STUFF;
    }
    if (error & HAL_CAN_ERROR_FOR) {
        return CAN_ERROR_FORM;
    }
    if (error & HAL_CAN_ERROR_ACK) {
        return CAN_ERROR_ACK;
    }
    if (error & HAL_CAN_ERROR_BR) {
        return CAN_ERROR_BIT_RECESSIVE;
    }
    if (error & HAL_CAN_ERROR_BD) {
        return CAN_ERROR_BIT_DOMINANT;
    }
    if (error & HAL_CAN_ERROR_CRC) {
        return CAN_ERROR_CRC;
    }
    if (error & HAL_CAN_ERROR_BOF) {
        return CAN_ERROR_BUS_OFF;
    }
    if (error & HAL_CAN_ERROR_EPV) {
        return CAN_ERROR_BUS_PASSIVE;
    }
    if (error & HAL_CAN_ERROR_EWG) {
        return CAN_ERROR_BUS_WARNING;
    }

    return CAN_ERROR_NONE;
}

/**
 * @brief CAN error handler
 */
static void CAN_ErrorHandler(void)
{
    CAN_ErrorType error = CAN_GetErrorType();

    if (error != CAN_ERROR_NONE) {
        can_status.error_count++;
        can_status.last_error = error;

        /* Call error callback if registered */
        if (error_callback != NULL) {
            error_callback(error);
        }
    }
}

